using System;
using System.Data;
using System.Data.SqlClient;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Web.Http;
using Newtonsoft.Json;

namespace MyApi
{
    public class UserController : ApiController
    {
        [HttpGet]
        public HttpResponseMessage SearchUsersByEmail(string email)
        {
            var connectionString = "Server=myserver;Database=mydatabase;User Id=myusername;Password=mypassword";
            using (var connection = new SqlConnection(connectionString))
            {
                connection.Open();
                var command = new SqlCommand("SELECT * FROM Users WHERE Email = @Email", connection);
                command.Parameters.AddWithValue("@Email", email);
                var reader = command.ExecuteReader();
                if (reader.HasRows)
                {
                    var users = new List<User>();
                    while (reader.Read())
                    {
                        users.Add(new User()
                        {
                            Id = reader["Id"].ToString(),
                            Email = reader["Email"].ToString(),
                            Name = reader["Name"].ToString()
                        });
                    }
                    return Request.CreateResponse(HttpStatusCode.OK, users);
                }
                else
                {
                    return Request.CreateResponse(HttpStatusCode.NotFound);
                }
            }
        }
    }
